{% comment %}
  This section is used in the cart template to render /cart page with an
  overview of the items in customer's cart.

  https://shopify.dev/docs/storefronts/themes/architecture/templates/cart
{% endcomment %}

<h1>{{ 'cart.title' | t }}</h1>

<form action="{{ routes.cart_url }}" method="post">
  <table>
    {% for item in cart.items %}
      <tr>
        <td>
          {% render 'image', image: item.image, url: item.url %}
        </td>
        <td>
          <p>{{ item.product.title }}</p>
          {{ 'cart.remove' | t | link_to: item.url_to_remove }}
        </td>
        <td>
          <input type="text" name="updates[]" value="{{ item.quantity }}">
          <input type="submit" value="{{ 'cart.update' | t }}">
        </td>
      </tr>
    {% endfor %}
  </table>

  <input type="submit" name="checkout" value="{{ 'cart.checkout' | t }}">
</form>

{% schema %}
{
  "name": "t:general.cart",
  "settings": []
}
{% endschema %}

{% if cart.items != empty %}
  <div class="offcanvas-footer pt-5">
    {% if cart.cart_level_discount_applications.size > 0 %}
      <ul 
        class="cart-discounts list-unstyled fs-xs mb-3 text-center alert alert-primary py-2 px-2" 
        aria-label="{{ 'cart.applied_discounts' | t }}">
        {% for discount in cart.cart_level_discount_applications %}
          <li class="">
            {% render 'svg-icons', icon: 'tag', size: 12, class: 'me-1' %}
            {{ discount.title }}
            (-{{ discount.total_allocated_amount | money }})
          </li>
        {% endfor %}
      </ul>
    {%- endif -%}
    <p class="cart-subtotal fs-5 mb-4" role="status">
      <span class="opacity-70 me-2">
        {{ 'cart.subtotal' | t }}: 
      </span>
      <span>
        {% if cart.items_subtotal_price > cart.total_price %}
          <s class="opacity-70 me-2">
            {{ cart.items_subtotal_price | money }}
          </s>
        {% endif %}
        <b>
          {{ cart.total_price | money }}
        </b>
      </span>
    </p>
    {% form 'cart', cart %}
      <button 
        class="btn btn-checkout btn-primary btn-lg" 
        name="checkout" 
        type="submit"
        onclick="this.classList.add('loading')">
        {% render 'svg-icons', icon: 'lock', size: 18, class: 'me-4' %}
        {{ 'cart.checkout' | t }}
      </button>
    {% endform %}
    <p class="small text-center mt-3 mb-n2 fst-italic">
      {{ 'cart.taxes_shipping_at_checkout_html' | t }}
    </p>
  </div>
{% endif %}

{% comment %}

  ========================================================================

  Liquid by Jason @ freakdesign.
  Questions? Ping me on twitter: @freakdesign

  Experimental code to sort a products in a collection by metafield value.
  Relates to this blog post: 
  http://freakdesign.com.au/blogs/news/sort-a-shopify-collection-by-total-inventory-per-product-with-liquid

  Demo:
  https://jasons-experiments.myshopify.com/collections/sort-by-inventory-levels

  We assume that:
  - the count of products is 50 or less
  - the pagination on the collection is set to a number higher than the product count 

  Note: This code was written for the Venture theme. 
  Adapt as needed.

  ========================================================================

{% endcomment %}

{% assign newArray = false %}
{% assign zeroFill = '0000' %}
{% assign zeroFillSize = zeroFill | size %}
{% for product in collection.products %}

  {% assign inventoryCount = 0 %}
  {% for variant in product.variants %}
    {% if variant.inventory_management != "shopify" %}{% continue %}{% endif %}
    {% assign inventoryCount = inventoryCount | plus:variant.inventory_quantity %}
  {% endfor %}

  {% assign indexCharSize = inventoryCount | append:'' | size %}
  {% assign toSlice = zeroFillSize | minus:indexCharSize %}
  {% assign tmpZeroFill = zeroFill | slice:0,toSlice %}
  {% assign newOrder = inventoryCount | default:'0' %}
  {% assign matrix = tmpZeroFill | append:newOrder | append:'.'  | append:forloop.index0 %}

  {% if newArray %}
    {% assign tmpIndex = matrix | split:',' %}
    {% assign newArray = newArray | concat:tmpIndex %}
  {% else %}
    {% assign newArray = matrix | split:',' %}
  {% endif %}

{% endfor %}

{% assign newArray = newArray | sort %}
{% for newArrayItem in newArray %}
  {% assign i = newArrayItem | split:'.' | last | abs %}
  {% assign grid = 'small--one-half medium-up--one-fifth' %}
  {% if paginationAmount == 1 %}
    {% assign grid = 'one-whole pagination_1' %}
  {% elsif paginationAmount == 2 %}
     {% assign grid = 'one-half pagination_2' %}
  {% elsif paginationAmount == 3 %}
     {% assign grid = 'small--one-half medium-up--one-third pagination_3' %}
  {% elsif paginationAmount == 4 %}
     {% assign grid = 'small--one-half medium-up--one-quarter' %}
  {% endif %}
  <div class="grid__item {{ grid }}">
    {% include 'product-card', product: collection.products[i] %}
  </div>
{% endfor %}

{% comment %}

	========================================================================

	Liquid by Jason @ freakdesign.
	Questions? Ping me on twitter: @freakdesign

	Experimental code to sort a products in a collection by metafield value.
	Relates to this blog post: 
	http://freakdesign.com.au/blogs/news/113614023-sort-products-in-a-shopify-collection-by-metafield-value-without-javascript

	We assume that:
	- the count of products is 50 or less
	- that every single product has been given a unique sorting numbers. 
	- the pagination on the collection is set to a number higher than the product count 

	========================================================================

{% endcomment %}

{% comment %}
	First set our new array to false...
{% endcomment %}
{% assign newArray = false %}

{% comment %}
	Set the starting zero fill. 
	This is actually bigger than needed but that's ok...
{% endcomment %}
{% assign zeroFill = '0000' %}

{% comment %}
	Set the length of the zero fill. We could manually add this number, but for 
	safety I am just getting Liquid to do it for me...
{% endcomment %}
{% assign zeroFillSize = zeroFill | size %}

{% comment %}
	Let's loop over the collection. We will not be using this to add anything 
	to the page at this point. This is to help us build up the matrix to 
	order by.
{% endcomment %}
{% for product in collection.products %}

	{% comment %}
		Get the length of the index
	{% endcomment %}
	{% assign indexCharSize = forloop.index0 | append:'' | size %}
	{% assign toSlice = zeroFillSize | minus:indexCharSize %}

	{% comment %}
		Slice the zeroFill as needed
	{% endcomment %}
	{% assign tmpZeroFill = zeroFill | slice:0,toSlice %}

	{% comment %}
		If there is no metafield assign a giant value 
		so that it gets pushed to the bottom
	{% endcomment %}
	{% assign newOrder = product.metafields.global.order | default:'999999' %}

	{% comment %}
		Build up the matrix. 
		It will look like xxxx.y (eg:0012.31) where xxxx is our zeroFill and y is the current order.
		This will hopefully make sense shortly...
	{% endcomment %}
	{% assign matrix = tmpZeroFill | append:newOrder | append:'.'  | append:forloop.index0 %}
	{% if newArray %}
		{% comment %}
			add a new value to our existing array.
		{% endcomment %}
		{% assign tmpIndex = matrix | split:',' %}
		{% assign newArray = newArray | concat:tmpIndex %}
	{% else %}
		{% comment %}
			Create the array with our *first* matrix value
		{% endcomment %}
		{% assign newArray = matrix | split:',' %}
	{% endif %}
{% endfor %}

{% comment %}
	Sort the array. Add in a reverse filter if you need to go the other direction.
	{% assign newArray = newArray | sort | reverse %}
{% endcomment %}
{% assign newArray = newArray | sort %}

{% comment %}
	Now that we have sorted the array we can loop over it grabbing each specific 
	item using its index#.
{% endcomment %}
{% for newArrayItem in newArray %}
	{% assign i = newArrayItem | split:'.' | last | abs %}
	<div>
		<h2>{{ collection.products[i].title }}</h2>
		<p>My original index was {{ i }}, but now it is {{ forloop.index0 }}</p>
	</div>
{% endfor %}

{% assign newArray = false %}
{% assign zeroFill = '0000' %}
{% assign zeroFillSize = zeroFill | size %}
{% for product in collection.products %}
	{% assign indexCharSize = forloop.index0 | append:'' | size %}
	{% assign toSlice = zeroFillSize | minus:indexCharSize %}
	{% assign tmpZeroFill = zeroFill | slice:0,toSlice %}
	{% assign newOrder = product.metafields.global.order | default:'999999' %}
	{% assign matrix = tmpZeroFill | append:newOrder | append:'.'  | append:forloop.index0 %}
	{% if newArray %}
		{% assign tmpIndex = matrix | split:',' %}
		{% assign newArray = newArray | concat:tmpIndex %}
	{% else %}
		{% assign newArray = matrix | split:',' %}
	{% endif %}
{% endfor %}
{% assign newArray = newArray | sort %}
{% for newArrayItem in newArray %}
	{% assign i = newArrayItem | split:'.' | last | abs %}
	<div>
		<h2>{{ collection.products[i].title }}</h2>
		<p>My original index was {{ i }}, but now it is {{ forloop.index0 }}</p>
	</div>
{% endfor %}

